# Python simulation of a Dividend Discount Model (DDM)
def stock_price_model(div, growth, discount_rate):
    # Gordon Growth Model: P = D1 / (k - g)
    return div / (discount_rate - growth)

fair_value = stock_price_model(2.5, 0.03, 0.08)
print(f'Estimated Fair Value: ${fair_value:.2f}')

def call_payoff(s, k):
    return max(s - k, 0)

strikes = [140, 150, 160]
price = 155
payoffs = [call_payoff(price, k) for k in strikes]
print(f'Payoffs: {payoffs}')

# Simple Delta approximation
def estimate_delta(p1, p2, s1, s2):
    return (p2 - p1) / (s2 - s1)

print(f'Est Delta: {estimate_delta(5.0, 5.5, 100, 101):.2f}')

# Gamma represents the rate of change of Delta
def calc_gamma(d1, d2, s1, s2):
    return (d2 - d1) / (s2 - s1)

print(f'Est Gamma: {calc_gamma(0.50, 0.55, 100, 101):.3f}')

# Option price vs Volatility
def vega_effect(base_p, vega, vol_change):
    return base_p + (vega * vol_change * 100)

print(f'New Price: ${vega_effect(10.0, 0.25, 0.05):.2f}')
